css:
.tn-header {
  margin-bottom: 8mm;
}
.tn-title {
  font-weight: 700;
  font-size: 14pt;
  margin: 0;
}
.tn-meta {
  color: #555;
  font-size: 9pt;
  margin-top: 1mm;
}
.tn-meta .sep {
  color: #aaa;
  padding: 0 1.5mm;
}
.tn-bemerkung {
  margin-top: 3mm;
  font-size: 9pt;
  color: #333;
  font-style: italic;
}
.tn-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 9pt;
}
.tn-table th {
  text-align: left;
  font-size: 8pt;
  color: #555;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  border-bottom: 0.4mm solid #333;
  padding: 1.5mm 2mm;
}
.tn-table td {
  padding: 1.8mm 2mm;
  vertical-align: top;
  border-bottom: 0.2mm solid #e5e5e5;
}
.tn-table tr.immobilie-row td {
  border-bottom: 0;
  padding-top: 5mm;
  padding-bottom: 1.5mm;
  font-weight: 700;
  font-size: 11pt;
  color: #111;
}
.tn-table tr.gebaeudeteil-row td {
  border-bottom: 0;
  padding-top: 2.5mm;
  padding-bottom: 0.8mm;
  font-weight: 600;
  font-size: 9pt;
  color: #444;
  background: #fafafa;
}
.tn-table tr.eintrag-row {
  break-inside: avoid;
}
.tn-wohnung {
  font-weight: 600;
  white-space: nowrap;
}
.tn-mieter-line {
  margin-bottom: 0.6mm;
}
.tn-mieter-line:last-child {
  margin-bottom: 0;
}
.tn-mieter {
  font-weight: 500;
}
.tn-rolle {
  color: #777;
  font-size: 8pt;
  margin-left: 1mm;
}
.tn-phone-block {
  margin-bottom: 0.6mm;
}
.tn-phone-block:last-child {
  margin-bottom: 0;
}
.tn-phone-label {
  color: #888;
  font-size: 8pt;
  margin-right: 1mm;
}
.tn-phone-item {
  white-space: nowrap;
}
.tn-phone-sep {
  color: #aaa;
  padding: 0 1.5mm;
}
.tn-empty {
  color: #aaa;
}

html:
{%- set groups = doc.get_grouped_eintraege() -%}
{%- set show_immobilie_groups = not doc.immobilie -%}
{%- set anzahl_eintraege = doc.eintraege|length -%}

<div class="tn-header">
  <h1 class="tn-title">{{ doc.titel or _("Telefonnummern Mieter") }}</h1>
  <div class="tn-meta">
    {{ _("Stichtag") }}: {{ frappe.utils.formatdate(doc.stichtag) }}
    {%- if doc.immobilie %}
      <span class="sep">·</span>{{ _("Immobilie") }}: {{ doc.immobilie }}
    {%- endif %}
    <span class="sep">·</span>{{ _("Einträge") }}: {{ anzahl_eintraege }}
  </div>
  {%- if doc.bemerkung %}
    <div class="tn-bemerkung">{{ doc.bemerkung }}</div>
  {%- endif %}
</div>

{%- if not groups %}
  <p class="tn-empty">{{ _("Keine Einträge vorhanden. Bitte im Formular auf \"Einträge laden\" klicken.") }}</p>
{%- else %}
  <table class="tn-table">
    <thead>
      <tr>
        <th style="width: 22%">{{ _("Wohnung") }}</th>
        <th style="width: 38%">{{ _("Mieter") }}</th>
        <th style="width: 40%">{{ _("Telefon / Mobil") }}</th>
      </tr>
    </thead>
    <tbody>
      {%- set ns = namespace(last_immobilie=None, last_gebaeudeteil=None) -%}
      {%- for grp in groups %}
        {%- set immobilie = grp.immobilie -%}
        {%- set gebaeudeteil_label = grp.gebaeudeteil or _("Ohne Gebäudeteil") -%}

        {%- if show_immobilie_groups and immobilie and immobilie != ns.last_immobilie %}
          <tr class="immobilie-row">
            <td colspan="3">{{ immobilie }}</td>
          </tr>
          {%- set ns.last_immobilie = immobilie -%}
          {%- set ns.last_gebaeudeteil = None -%}
        {%- endif %}

        {%- if gebaeudeteil_label != ns.last_gebaeudeteil %}
          <tr class="gebaeudeteil-row">
            <td colspan="3">{{ gebaeudeteil_label }}</td>
          </tr>
          {%- set ns.last_gebaeudeteil = gebaeudeteil_label -%}
        {%- endif %}

        <tr class="eintrag-row">
          <td class="tn-wohnung">{{ grp.wohnung }}</td>
          <td>
            {%- for m in grp.mieter %}
              <div class="tn-mieter-line">
                <span class="tn-mieter">{{ m.name }}</span>
                {%- if m.rolle and m.rolle != 'Hauptmieter' %}
                  <span class="tn-rolle">({{ m.rolle }})</span>
                {%- endif %}
              </div>
            {%- endfor %}
          </td>
          <td>
            {%- for m in grp.mieter %}
              <div class="tn-phone-block">
                {%- if m.telefon %}<span class="tn-phone-item"><span class="tn-phone-label">{{ _("Tel.") }}</span>{{ m.telefon }}</span>{%- endif %}
                {%- if m.telefon and m.mobil %}<span class="tn-phone-sep">·</span>{%- endif %}
                {%- if m.mobil %}<span class="tn-phone-item"><span class="tn-phone-label">{{ _("Mob.") }}</span>{{ m.mobil }}</span>{%- endif %}
                {%- if not m.telefon and not m.mobil %}<span class="tn-empty">—</span>{%- endif %}
              </div>
            {%- endfor %}
          </td>
        </tr>
      {%- endfor %}
    </tbody>
  </table>
{%- endif %}
